func contributorDisplay(c bbl.WorkContributor) string {
	roles := strings.Join(c.Roles, ", ")
	name := c.Name
	if name == "" && c.FamilyName != "" {
		name = c.FamilyName
		if c.GivenName != "" {
			name += ", " + c.GivenName
		}
	}
	if name == "" {
		name = "(unnamed)"
	}
	if roles != "" {
		return name + " (" + roles + ")"
	}
	return name
}
